import { IEndpoint } from "../common/communicator";
import { uuid } from "../common/uuid";

export class BroadcastChannelPolyfill implements IEndpoint {
    private listeners: Array<(message) => void> = [];
    private storage = window.localStorage;
    private prefix: string;
    private listening = true;
    private _tabId = uuid();
    constructor(channelID: string) {
        this.prefix = "__sd_interop_" + channelID;
        window.addEventListener("storage", (e) => {
            if (!this.listening) {
                return;
            }
            if (e.key.indexOf(this.prefix) === 0) {
                try {
                    const data = JSON.parse(e.newValue);
                    if (data._tabId !== this._tabId) {
                        this.listeners.forEach((listener) => {
                            listener({ data: e.newValue });
                        });
                    }
                } catch (error) {
                    console.error("An exception occurred while receiving a broadcasted message!");
                }
            }
        });
    }
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    public postMessage(message: any): void {
        const key = this.prefix + uuid();
        this.listening = false;
        try {
            if (this.storage.getItem(key) === null) {
                const data = JSON.parse(message);
                data._tabId = this._tabId;
                this.storage.setItem(key, JSON.stringify(data));
                this.storage.removeItem(key);
            }
        } catch (error) {
            console.error("Broadcast polyfill can not function properly!");
        }
        this.listening = true;
    }
    public addEventListener(type: string, listener: (message) => void): void {
        if (type === "message") {
            this.listeners.push(listener);
        }
    }
    public removeEventListener(type: string, listener: (message) => void): void {
        if (type === "message") {
            const index = this.listeners.indexOf(listener);
            if (index > -1) {
                this.listeners.splice(index);
            }
        }
    }
}

export interface IBroadCastEndpoint {
    postMessage(message: unknown): void;
    addEventListener(type: string, listener: (message) => void, options?: boolean | AddEventListenerOptions): void;
    removeEventListener(type: string, listener: (message) => void, options?: boolean | AddEventListenerOptions): void;
}

export const createBroadcastEndPoint = (channelID: string): IBroadCastEndpoint => {
    if ("BroadcastChannel" in window) {
        return new BroadcastChannel(channelID);
    }
    return new BroadcastChannelPolyfill(channelID);
};
