import { SDMessage } from "../common/sdmessage";
import { createBroadcastEndPoint } from "./broadcastchannel";
import { uuid } from "../common/uuid";

const whitelist = [window.location.origin, "WHITELIST"];
const interop = createBroadcastEndPoint("smartdesign-interop");
const referrer = new URL(document.referrer);
const myOrigin = referrer.origin;
const tunnelInstanceID = uuid();

interop.addEventListener("message", (e: MessageEvent) => {
    if (whitelist.indexOf(myOrigin) > -1) {
        try {
            const message: SDMessage = e.data ? (JSON.parse(e.data) as SDMessage) : undefined;
            if ((message && message.target == null) || message.target === tunnelInstanceID) {
                window.parent.postMessage(JSON.stringify(message), myOrigin);
            }
        } catch (error) {
            console.error("An exception occurred while broadcasting the message!");
        }
    }
});

window.addEventListener("message", (e) => {
    if (whitelist.indexOf(e.origin) > -1) {
        const message: SDMessage = e.data ? (JSON.parse(e.data) as SDMessage) : undefined;
        if (message) {
            if (message.payload) {
                message.payload.origin = e.origin;
            }
            if (message.source == null) {
                message.source = tunnelInstanceID;
            } else {
                const sender = message.source;
                message.source = tunnelInstanceID;
                message.target = sender;
            }
            interop.postMessage(JSON.stringify(message));
        }
    }
});

window.parent.postMessage("ready", myOrigin);
